import React, { createContext, useContext, useState } from "react";

const AppContext = createContext(null);

const USER_STORAGE_KEY = "agenticUser";
const MAILBOX_STORAGE_KEY = "agenticUserEmail";

const loadStoredUser = () => {
  try {
    const stored = localStorage.getItem(USER_STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch {
    return null;
  }
};

const loadStoredMailboxEmail = () => {
  try {
    return localStorage.getItem(MAILBOX_STORAGE_KEY) || "";
  } catch {
    return "";
  }
};

export const AppProvider = ({ children }) => {
  const [user, setUserState] = useState(loadStoredUser);
  const [userEmail, setUserEmailState] = useState(loadStoredMailboxEmail);
  const [loading, setLoading] = useState(false);

  const setUser = (userData) => {
    setUserState(userData);
    if (userData) {
      localStorage.setItem(USER_STORAGE_KEY, JSON.stringify(userData));
    } else {
      localStorage.removeItem(USER_STORAGE_KEY);
    }
  };

  const setUserEmail = (email) => {
    const value = email || "";
    setUserEmailState(value);
    if (value) {
      localStorage.setItem(MAILBOX_STORAGE_KEY, value);
    } else {
      localStorage.removeItem(MAILBOX_STORAGE_KEY);
    }
  };

  const logout = () => {
    setUser(null);
    setUserEmail("");
  };

  return (
    <AppContext.Provider
      value={{
        user,
        setUser,
        userEmail,
        setUserEmail,
        logout,
        loading,
        setLoading,
      }}
    >
      {children}
    </AppContext.Provider>
  );
};

export const useApp = () => {
  const ctx = useContext(AppContext);
  if (!ctx) throw new Error("useApp must be used within AppProvider");
  return ctx;
};
